var result = [];
java.toast("🔥正在刷新列表,请稍等！");
var push = (title, url, size) => result.push({
  "title": title,
  "url": url,
  "style": {
    "layout_flexGrow": 1,
    "layout_flexBasisPercent": size
  }
});

var fl = java.ajax("https://m.lulushuwu.com/xiaoshuodaquan");

if (fl) {

  a = org.jsoup.Jsoup.parse(fl).select(".typelist a")
push("🔥分类小说🔥",null,1)
    for(var i=0;i<a.length;i++){
        title=a[i].text()
        url=a[i].attr("href")
        size=0.33;
        title = String(title).replace(/\s/g, "");
        url=baseUrl+String(url).replace(/\d+\/$/,"")+"/page_{{page}}.html";
        push(title,url,size)
    };
} else {

  java.toast("🤔列表刷新失败！！！");
}
JSON.stringify(result);

